  ('pukao-e3452428-moex-00422', 'pukao-e3452428', 'pukao-e3452428-moex-111-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '有關直轄市議會組織之敘述，下列何者錯誤？', '["直轄市議員由直轄市民依法選舉之，任期4年，連選得連任", "直轄市議員之選舉區原則上以「地」為基礎劃分之，但由原住民選出者，以其行政區域內之原住民為 選舉區", "各選舉區選出議員代表名額達4人者，應有婦女當選名額1人；超過4人者，每增加4人增1人", "直轄市議會置議長、副議長各1人，由直轄市議員以不記名投票分別互選或罷免之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:22+00:00", "source_pdf_sha1": "c9394e34f469", "answer_pdf_sha1": "b714be457b7c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "402", "s": "0309", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
